input.command:
cat <<'EOF' | agent-browser --session browser-qa-liatrio-ai eval --stdin
const imgs = Array.from(document.images);
const broken = imgs.filter(i => i.complete && i.naturalWidth === 0).map(i => i.src);
const noAlt = imgs.filter(i => !i.alt && !i.getAttribute('aria-hidden')).map(i => i.src);
({total: imgs.length, broken, noAltCount: noAlt.length, noAltSample: noAlt.slice(0,5)})
EOF

