input.command:
cat <<'EOF' | agent-browser --session browser-qa-liatrio-ai eval --stdin
// Keyboard focus check: tab from body, see what gets focused first
document.body.focus();
const results = [];
for (let i = 0; i < 5; i++) {
  const e = new KeyboardEvent('keydown', {key: 'Tab'});
  document.activeElement.dispatchEvent(e);
}
const a = document.activeElement;
({active: a.tagName, text: a.innerText?.slice(0,60), outline: getComputedStyle(a).outline})
EOF

